import{_ as a,o as i,c as o,a0 as d}from"./chunks/framework.Cl79jK2u.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),t={name:"changelog.md"};function n(l,e,r,c,s,h){return i(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to Moxie are documented here.</p><h2 id="_0-2-1-2026-03-22" tabindex="-1">[0.2.1] - 2026-03-22 <a class="header-anchor" href="#_0-2-1-2026-03-22" aria-label="Permalink to &quot;[0.2.1] - 2026-03-22&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Schedule abstraction with canonical trigger model, <code>--every</code> interval UX, <code>fire</code> execution entrypoint, and backend reconciliation layer</li><li>macOS launchd schedule backend with one-shot year-precision guard and fallback-reason preservation</li><li>Windows Task Scheduler schedule backend (tolerates missing deletes on cleanup)</li><li>Portable cron normalization for cross-platform schedule definitions</li><li><code>moxie subagent list</code>, <code>show</code>, and <code>cancel</code> subcommands for managing background work</li><li>Synthesis continuation loop — sequential tasks now auto-dispatch the next step instead of stopping after summary</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Progress stall timeout disabled by default to avoid false positives on long-running subagent tasks</li><li>Docs refreshed: home quick-start, service notes, Windows scheduler status, schedule rollout cleanup</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Hardened continuation loop to avoid duplicate dispatches and handle edge cases from code review</li></ul><h2 id="_0-2-1-2026-03-22-1" tabindex="-1">[0.2.1] - 2026-03-22 <a class="header-anchor" href="#_0-2-1-2026-03-22-1" aria-label="Permalink to &quot;[0.2.1] - 2026-03-22&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Synthesis continuation loop: when a user requests multiple sequential tasks, the synthesis step now automatically dispatches the next task instead of just summarizing and stopping</li><li><code>moxie subagent list</code>, <code>moxie subagent show</code>, and <code>moxie subagent cancel</code> commands for inspecting and managing running subagent jobs</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Schedule abstraction with first-class <code>--every</code> interval UX, canonical trigger model, cron normalization, backend reconciliation, and <code>fire</code> execution entrypoint</li><li>macOS launchd schedule backend with one-shot year precision guard and fallback reason preservation</li><li>Windows Task Scheduler schedule backend with tolerant delete handling</li><li>Progress stall timeout now disabled by default for dispatched subagents</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Hardened synthesis continuation loop per code review feedback</li></ul><h2 id="_0-2-0-2026-03-22" tabindex="-1">[0.2.0] - 2026-03-22 <a class="header-anchor" href="#_0-2-0-2026-03-22" aria-label="Permalink to &quot;[0.2.0] - 2026-03-22&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Supervised subagent execution with config-driven retry/backoff, stall detection, progress timeouts, and terminal escalation after repeated failure</li><li>Persisted subagent supervision state for attempts, active run IDs, and last-seen event/progress timestamps</li><li>Blocking subagent failure recovery so nested parent runs are unblocked immediately instead of hanging until timeout</li></ul><h3 id="changed-2" tabindex="-1">Changed <a class="header-anchor" href="#changed-2" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Moxie now consumes <code>oneagent v0.11.11</code> telemetry with per-run IDs, timestamps, start events, and heartbeats</li><li>Subagent dispatch now serializes work by backend thread ID when available, preventing same-thread races across subagent and synthesis paths</li><li>Nested <code>moxie subagent</code> calls now prefer the immediate parent job via <code>MOXIE_JOB_ID</code> and block until child completion</li><li>Synthesis is queued instead of running inline on the parent thread</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Stale subagent attempt events/results no longer overwrite the active attempt outcome</li><li>Hanging or discarded blocking child jobs now surface deterministic failure results back to their waiting parent</li></ul><h2 id="_0-1-10-2026-03-21" tabindex="-1">[0.1.10] - 2026-03-21 <a class="header-anchor" href="#_0-1-10-2026-03-21" aria-label="Permalink to &quot;[0.1.10] - 2026-03-21&quot;">​</a></h2><h3 id="changed-3" tabindex="-1">Changed <a class="header-anchor" href="#changed-3" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Bumped <code>oneagent</code> to <code>v0.11.10</code></li></ul><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Codex subagents now inherit the backend-agnostic <code>oneagent</code> template fix for empty inline assignment args, preventing <code>exit status 1</code> when thinking is unset</li></ul><h2 id="_0-1-9-2026-03-21" tabindex="-1">[0.1.9] - 2026-03-21 <a class="header-anchor" href="#_0-1-9-2026-03-21" aria-label="Permalink to &quot;[0.1.9] - 2026-03-21&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Configurable <code>default_cwd</code> with platform-specific managed workspace defaults for Linux and macOS</li></ul><h3 id="changed-4" tabindex="-1">Changed <a class="header-anchor" href="#changed-4" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>moxie init</code> now prompts for a default workspace and can install the service against that configured default</li><li><code>moxie serve</code> now prefers an explicit <code>--cwd</code>, then the current shell directory, then <code>default_cwd</code>, then the platform workspace default</li><li><code>moxie service install</code> now uses the service manager working directory instead of passing <code>--cwd</code> to <code>moxie serve</code></li><li>README and docs now emphasize the service-first setup flow and remove internal <code>oneagent</code>/<code>oa list</code> references from user-facing guidance</li></ul><h3 id="fixed-4" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-4" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>User-facing docs now match actual <code>/cwd</code> behavior for named workspaces</li></ul><h2 id="_0-1-8-2026-03-22" tabindex="-1">[0.1.8] - 2026-03-22 <a class="header-anchor" href="#_0-1-8-2026-03-22" aria-label="Permalink to &quot;[0.1.8] - 2026-03-22&quot;">​</a></h2><h3 id="fixed-5" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-5" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>LaunchAgent installs now capture <code>PATH</code> and <code>HOME</code> so backend CLIs remain available when Moxie runs under <code>launchd</code></li></ul><h2 id="_0-1-7-2026-03-21" tabindex="-1">[0.1.7] - 2026-03-21 <a class="header-anchor" href="#_0-1-7-2026-03-21" aria-label="Permalink to &quot;[0.1.7] - 2026-03-21&quot;">​</a></h2><h3 id="fixed-6" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-6" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>LaunchAgent installs now prefer the stable <code>moxie</code> path from <code>PATH</code> instead of a versioned Homebrew Cellar path</li></ul><h3 id="changed-5" tabindex="-1">Changed <a class="header-anchor" href="#changed-5" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>moxie service install</code>, <code>start</code>, <code>stop</code>, <code>uninstall</code>, <code>restart</code>, and <code>reload</code> now print explicit confirmation messages on success</li></ul><h2 id="_0-1-6-2026-03-21" tabindex="-1">[0.1.6] - 2026-03-21 <a class="header-anchor" href="#_0-1-6-2026-03-21" aria-label="Permalink to &quot;[0.1.6] - 2026-03-21&quot;">​</a></h2><h3 id="added-4" tabindex="-1">Added <a class="header-anchor" href="#added-4" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>moxie service install</code> and <code>moxie service uninstall</code> for native service definition management</li><li>Optional service install/start flow during <code>moxie init</code></li></ul><h3 id="changed-6" tabindex="-1">Changed <a class="header-anchor" href="#changed-6" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>moxie init</code> can now collect a default service working directory when installing a background service</li></ul><h2 id="_0-1-5-2026-03-21" tabindex="-1">[0.1.5] - 2026-03-21 <a class="header-anchor" href="#_0-1-5-2026-03-21" aria-label="Permalink to &quot;[0.1.5] - 2026-03-21&quot;">​</a></h2><h3 id="fixed-7" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-7" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Windows cross-build compatibility for the macOS launchd reload path</li></ul><h2 id="_0-1-4-2026-03-21" tabindex="-1">[0.1.4] - 2026-03-21 <a class="header-anchor" href="#_0-1-4-2026-03-21" aria-label="Permalink to &quot;[0.1.4] - 2026-03-21&quot;">​</a></h2><h3 id="added-5" tabindex="-1">Added <a class="header-anchor" href="#added-5" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>macOS <code>launchd</code> support for <code>moxie service start|stop|restart|reload|status</code></li><li>LaunchAgent documentation for <code>~/Library/LaunchAgents/io.github.1broseidon.moxie.plist</code></li></ul><h3 id="changed-7" tabindex="-1">Changed <a class="header-anchor" href="#changed-7" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>macOS service control now follows the per-user LaunchAgent model instead of failing through <code>systemctl</code></li></ul><h2 id="_0-1-3-2026-03-21" tabindex="-1">[0.1.3] - 2026-03-21 <a class="header-anchor" href="#_0-1-3-2026-03-21" aria-label="Permalink to &quot;[0.1.3] - 2026-03-21&quot;">​</a></h2><h3 id="changed-8" tabindex="-1">Changed <a class="header-anchor" href="#changed-8" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Service lifecycle commands now live under <code>moxie service ...</code> instead of top-level <code>moxie start|stop|restart|reload|status</code></li><li>Non-Linux platforms now get a clear service-manager error instead of attempting to invoke <code>systemctl</code></li></ul><h2 id="_0-1-2-2026-03-21" tabindex="-1">[0.1.2] - 2026-03-21 <a class="header-anchor" href="#_0-1-2-2026-03-21" aria-label="Permalink to &quot;[0.1.2] - 2026-03-21&quot;">​</a></h2><h3 id="added-6" tabindex="-1">Added <a class="header-anchor" href="#added-6" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Top-level <code>moxie start</code>, <code>stop</code>, <code>restart</code>, <code>reload</code>, and <code>status</code> commands for user service control</li><li>In-process <code>SIGHUP</code> reload support for <code>moxie serve</code> so config and backend definitions can be reloaded without exiting the process</li></ul><h3 id="changed-9" tabindex="-1">Changed <a class="header-anchor" href="#changed-9" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Backend prompts now frame Claude, Codex, and other backends as operating on behalf of Moxie</li><li>Capability descriptions are guided toward local CLI behavior and user-facing Moxie features instead of harness-centric language</li><li><code>poll</code> and <code>cursor</code> are now documented as operator/debug commands instead of primary user commands</li></ul><h3 id="fixed-8" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-8" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Release workflow can now be manually dispatched for an existing tag</li><li>Homebrew tap publishing path was validated and backfilled</li><li>Prompt injection tests now allow the backend identity suffix added to system prompts</li></ul><h2 id="_0-1-0-2026-03-20" tabindex="-1">[0.1.0] - 2026-03-20 <a class="header-anchor" href="#_0-1-0-2026-03-20" aria-label="Permalink to &quot;[0.1.0] - 2026-03-20&quot;">​</a></h2><p>Initial public release.</p><h3 id="added-7" tabindex="-1">Added <a class="header-anchor" href="#added-7" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Telegram transport with long polling, HTML formatting, photo handling, and file attachments</li><li>Slack transport with Socket Mode, mrkdwn formatting, and thread support</li><li>Multi-backend dispatch via oneagent (Claude, Codex, Gemini, Pi, OpenCode)</li><li><code>/model</code> command to switch backends and models per conversation</li><li><code>/think</code> command for reasoning effort control (low/medium/high)</li><li><code>/cwd</code> command with named workspaces</li><li><code>/new</code> and <code>/threads</code> for thread management</li><li><code>/compact</code> for thread compaction</li><li>Schedules with one-shot (<code>--in</code>, <code>--at</code>) and recurring (<code>--cron</code>) triggers</li><li>Subagent delegation with synthesis back to parent conversation</li><li>Paragraph-aware message chunking for long responses</li><li>Activity status messages during dispatch</li><li>Job persistence and recovery across restarts</li><li>systemd service support</li></ul>',70)])])}const g=a(t,[["render",n]]);export{m as __pageData,g as default};
